import type { ISudokuState } from './state'

export enum SudokuActionType {
  // Restart game.
  RESTART = '@kyokuya/sudoku/restart',

  // Reset game.
  RESET = '@kyokuya/sudoku/reset',

  // Start game.
  START = '@kyokuya/sudoku/start',

  // Pause game.
  PAUSE = '@kyokuya/sudoku/pause',

  // Resume game.
  RESUME = '@kyokuya/sudoku/resume',

  // Game finished.
  FINISHED = '@kyokuya/sudoku/finished',

  // CHANGE the activated board cell.
  ACTIVE = '@kyokuya/sudoku/active',

  // Asking for a hint.
  HINT = '@kyokuya/sudoku/hint',

  // Requesting to view the cheat.
  TOGGLE_CHEAT_VISIBILITY = '@kyokuya/sudoku/toggle-cheat-visibility',

  // Input into a board cell.
  INPUT = '@kyokuya/sudoku/input',
}

export type ISudokuAction =
  | {
      type: SudokuActionType.RESTART
    }
  | {
      type: SudokuActionType.RESET
      payload: {
        SUDOKU_SIZE_SQRT?: ISudokuState['SUDOKU_SIZE_SQRT']
        difficulty?: ISudokuState['difficulty']
        radix?: ISudokuState['radix']
      }
    }
  | {
      type: SudokuActionType.START
    }
  | {
      type: SudokuActionType.PAUSE
    }
  | {
      type: SudokuActionType.RESUME
    }
  | {
      type: SudokuActionType.FINISHED
      payload: number // score
    }
  | {
      type: SudokuActionType.ACTIVE
      payload: { r: number; c: number }
    }
  | {
      type: SudokuActionType.HINT
    }
  | {
      type: SudokuActionType.TOGGLE_CHEAT_VISIBILITY
      payload?: boolean
    }
  | {
      type: SudokuActionType.INPUT
      payload: number
    }
