import PropTypes from 'prop-types'
import React from 'react'

export interface ISudokuBoardBorders {
  /**
   * Sudoku size, sqrt of the number of rows or columns.
   */
  SUDOKU_SIZE_SQRT: number
}

export const SudokuBoardBorders: React.FC<ISudokuBoardBorders> = React.memo(
  ({ SUDOKU_SIZE_SQRT }) => {
    const SUDOKU_SIZE = SUDOKU_SIZE_SQRT * SUDOKU_SIZE_SQRT
    const borders: React.ReactNode[] = []
    for (let i = SUDOKU_SIZE_SQRT, j = -1; i < SUDOKU_SIZE; i += SUDOKU_SIZE_SQRT, ++j) {
      const position = `calc(${i} * var(--kyokuya-sudoku__board-cell-size) + ${i + j}px)`
      borders.push(
        <div
          key={`h-${i}`}
          className="kyokuya-sudoku__board-horizontal-border"
          style={{ top: position }}
        />,
      )
      borders.push(
        <div
          key={`v-${i}`}
          className="kyokuya-sudoku__board-vertical-border"
          style={{ left: position }}
        />,
      )
    }
    return <React.Fragment>{borders}</React.Fragment>
  },
  (prevProps, props) => prevProps.SUDOKU_SIZE_SQRT === props.SUDOKU_SIZE_SQRT,
)

SudokuBoardBorders.propTypes = {
  SUDOKU_SIZE_SQRT: PropTypes.number.isRequired,
}

SudokuBoardBorders.displayName = 'SudokuBoardBorders'
export default SudokuBoardBorders
