import type { ISudokuBoard } from '@algorithm.ts/sudoku'
import { copySudokuBoard, createSudokuBoard } from '@algorithm.ts/sudoku'
import { GameRunningStatus } from '@kyokuya/react-game-core'
import type React from 'react'
import { getSudokuCreator } from '../util/creator'
import { findCandidateHintCell } from '../util/hint'
import { SudokuActionType } from './action'
import type { ISudokuAction } from './action'
import type { ISudokuState } from './state'

export const reducer: React.Reducer<ISudokuState, ISudokuAction> = (
  state: ISudokuState,
  action: ISudokuAction,
): ISudokuState => {
  switch (action.type) {
    case SudokuActionType.RESTART: {
      const { SUDOKU_SIZE_SQRT, difficulty, attempt } = state

      const creator = getSudokuCreator(SUDOKU_SIZE_SQRT)
      const { puzzle, solution } = creator.createSudoku(difficulty)

      // initialize.
      copySudokuBoard(puzzle, attempt as ISudokuBoard)

      return {
        ...state,
        gameStatus: GameRunningStatus.PENDING,
        gameTick: state.gameTick + 1,
        puzzle,
        solution,
        hintCell: { r: -1, c: -1, v: -1 },
        hintTick: 0,
        attemptTick: 0,
      }
    }
    case SudokuActionType.RESET: {
      const {
        difficulty = state.difficulty,
        SUDOKU_SIZE_SQRT = state.SUDOKU_SIZE_SQRT,
        radix = state.radix,
      } = action.payload

      // It's only necessary to regenerate the data if the the difficulty
      // or size changed,
      if (difficulty === state.difficulty && SUDOKU_SIZE_SQRT === state.SUDOKU_SIZE_SQRT) {
        return radix === state.radix ? state : { ...state, radix }
      }

      const SUDOKU_SIZE = SUDOKU_SIZE_SQRT * SUDOKU_SIZE_SQRT
      const creator = getSudokuCreator(SUDOKU_SIZE_SQRT)
      const { puzzle, solution } = creator.createSudoku(difficulty / 100)

      let attempt = state.attempt

      if (SUDOKU_SIZE_SQRT === state.SUDOKU_SIZE_SQRT) {
        copySudokuBoard(puzzle, attempt as ISudokuBoard)
      } else {
        attempt = createSudokuBoard(SUDOKU_SIZE)
        copySudokuBoard(puzzle, attempt as ISudokuBoard)
      }

      return {
        SUDOKU_SIZE_SQRT,
        difficulty,
        radix,
        gameStatus: GameRunningStatus.PENDING,
        score: state.score,
        puzzle,
        solution,
        attempt,
        activatedCell: state.activatedCell,
        hintCell: { r: -1, c: -1, v: -1 },
        cheatVisible: false,
        gameTick: state.gameTick + 1,
        attemptTick: 0,
        hintTick: 0,
      }
    }
    case SudokuActionType.START: {
      // Not in pending state.
      if (state.gameStatus !== GameRunningStatus.PENDING) return state
      return { ...state, gameStatus: GameRunningStatus.RUNNING }
    }
    case SudokuActionType.PAUSE: {
      // Not in running state.
      if (state.gameStatus !== GameRunningStatus.RUNNING) return state
      return { ...state, gameStatus: GameRunningStatus.PAUSED }
    }
    case SudokuActionType.RESUME: {
      // Not in paused state.
      if (state.gameStatus !== GameRunningStatus.PAUSED) return state
      return { ...state, gameStatus: GameRunningStatus.RUNNING }
    }
    case SudokuActionType.FINISHED: {
      // Not in running state.
      if (state.gameStatus !== GameRunningStatus.RUNNING) return state
      const score = Math.round(action.payload)
      return {
        ...state,
        gameStatus: GameRunningStatus.FINISHED,
        score: state.score + Math.max(5, score),
      }
    }
    case SudokuActionType.ACTIVE: {
      const { r, c } = action.payload
      const { activatedCell } = state
      if (activatedCell.r === r && activatedCell.c === c) return state
      return { ...state, activatedCell: { r, c } }
    }
    case SudokuActionType.HINT: {
      const { SUDOKU_SIZE_SQRT, puzzle, solution, attempt, activatedCell } = state

      // Prefer current activated cell.
      const hintCell =
        activatedCell.r > -1 && puzzle[activatedCell.r][activatedCell.c] === -1
          ? activatedCell
          : findCandidateHintCell(SUDOKU_SIZE_SQRT * SUDOKU_SIZE_SQRT, attempt, puzzle, solution)

      // Cannot found a valid hint cell
      if (hintCell === null) return state

      const { r, c } = hintCell
      if (state.hintCell.r === r && state.hintCell.c === c) {
        return { ...state, hintTick: state.hintTick + 1 }
      }

      const v = r >= 0 && c >= 0 ? solution[r][c] : -1
      return { ...state, hintCell: { r, c, v }, hintTick: state.hintTick + 1 }
    }
    case SudokuActionType.TOGGLE_CHEAT_VISIBILITY: {
      if (action.payload === state.cheatVisible) return state
      const cheatVisible = action.payload ?? !state.cheatVisible
      return { ...state, cheatVisible }
    }
    case SudokuActionType.INPUT: {
      // Not in running state.
      if (state.gameStatus !== GameRunningStatus.RUNNING) return state

      const v = action.payload
      const SUDOKU_SIZE = state.SUDOKU_SIZE_SQRT ** 2

      // Invalid input
      if (!Number.isInteger(v) || v < -1 || v >= SUDOKU_SIZE) return state

      const { r, c } = state.activatedCell
      if (r < 0 || c < 0) return state

      // Cannot modify the content on the preset cell.
      if (state.puzzle[r][c] !== -1) return state

      // Nothing changed.
      if (state.attempt[r][c] === v) return state

      const { attempt, attemptTick, activatedCell } = state

      // Following two modification is intended.
      attempt[r][c] = v

      return {
        ...state,
        attemptTick: attemptTick + 1,
        activatedCell: activatedCell.r === r && activatedCell.c ? activatedCell : { r, c },
      }
    }
    default:
      return state
  }
}
