import { ElapsedTimer, GameRunningStatus } from '@kyokuya/react-game-core'
import { SudokuActionType, SudokuContextType } from '@kyokuya/react-game-sudoku-core'
import HintIcon from '@mui/icons-material/EmojiObjects'
import GameRunningIcon from '@mui/icons-material/Pause'
import RefreshIcon from '@mui/icons-material/Refresh'
import TimerIcon from '@mui/icons-material/Timer'
import VisibilityIcon from '@mui/icons-material/Visibility'
import { Button, Dialog, DialogActions, DialogContent, IconButton, Tooltip } from '@mui/material'
import PropTypes from 'prop-types'
import React from 'react'

export interface IGameToolbarProps {
  containerRef: React.RefObject<HTMLDivElement>
}

export const GameToolbar: React.FC<IGameToolbarProps> = React.memo(
  props => {
    const { containerRef } = props
    const { state, dispatch } = React.useContext(SudokuContextType)
    const { score, gameStatus } = state

    const [restartDialogVisible, setRestartDialogVisible] = React.useState<boolean>(false)

    // Show cheat
    const showCheat = React.useCallback(() => {
      dispatch({ type: SudokuActionType.TOGGLE_CHEAT_VISIBILITY, payload: true })
    }, [dispatch])

    // Restart game.
    const restartGame = React.useCallback(() => {
      setRestartDialogVisible(false)
      dispatch({ type: SudokuActionType.RESTART })
    }, [dispatch])

    // Pause game.
    const pauseGame = React.useCallback(() => {
      dispatch({ type: SudokuActionType.PAUSE })
    }, [dispatch])

    return (
      <div className="kyokuya-sudoku__toolbar">
        <div className="kyokuya-sudoku__toolbar-item kyokuya-sudoku__toolbar-item-buttons">
          <Button
            variant="contained"
            color="inherit"
            startIcon={<RefreshIcon />}
            onClick={() =>
              gameStatus === GameRunningStatus.PENDING || gameStatus === GameRunningStatus.FINISHED
                ? restartGame()
                : setRestartDialogVisible(true)
            }
          >
            New
          </Button>
          <Button
            variant="contained"
            color="inherit"
            disabled={gameStatus !== 'running'}
            startIcon={<HintIcon />}
            onClick={() => dispatch({ type: SudokuActionType.HINT })}
          >
            HINT
          </Button>
          <Button
            variant="contained"
            color="secondary"
            disabled={gameStatus !== 'running'}
            startIcon={<VisibilityIcon />}
            onClick={showCheat}
          >
            Cheat
          </Button>
        </div>
        <div className="kyokuya-sudoku__toolbar-item kyokuya-sudoku__toolbar-item-state">
          <div key="state-buttons" className="kyokuya-sudoku__toolbar-state-buttons">
            {gameStatus === 'running' && (
              <Tooltip title="Pause">
                <IconButton color="primary" onClick={pauseGame}>
                  <GameRunningIcon />
                </IconButton>
              </Tooltip>
            )}
          </div>
          <div key="elapsed-time" className="kyokuya-sudoku__toolbar-elapsed-time">
            <Tooltip title="Time used">
              <TimerIcon />
            </Tooltip>
            &nbsp;&nbsp;
            <ElapsedTimer gameStatus={gameStatus} />
          </div>
          <div key="score" className="kyokuya-sudoku__toolbar-score">
            Score: {score}
          </div>
        </div>
        <Dialog
          container={containerRef.current}
          open={restartDialogVisible}
          onClose={() => setRestartDialogVisible(false)}
          aria-labelledby="confirm-to-restart"
        >
          <DialogContent>Are you sure you want to start a new game?</DialogContent>
          <DialogActions>
            <Button color="inherit" onClick={() => setRestartDialogVisible(false)}>
              Cancel
            </Button>
            <Button color="primary" onClick={restartGame}>
              Confirm
            </Button>
          </DialogActions>
        </Dialog>
      </div>
    )
  },
  (prevProps, props) => prevProps.containerRef === props.containerRef,
)

GameToolbar.displayName = 'SudokuGameToolbar'

GameToolbar.propTypes = {
  containerRef: PropTypes.any.isRequired,
}
