import type { ISudokuState } from '@kyokuya/react-game-sudoku-core'
import { SudokuContextProvider, SudokuContextType } from '@kyokuya/react-game-sudoku-core'
import type { IStorage } from '@kyokuya/react-storage'
import { createLocalStorage, useInitialData } from '@kyokuya/react-storage'
import CircularProgress from '@mui/material/CircularProgress'
import PropTypes from 'prop-types'
import React from 'react'
import { usePersistSudokuStateEffect } from './hook/usePersistSudokuStateEffect'
import { SudokuGameMain } from './SudokuGameMain'

export interface ISudokuGameProps {
  storageKey?: string
  initialContextData?: Partial<ISudokuState>
}

export const SudokuGame: React.FC<ISudokuGameProps> = props => {
  const { storageKey, initialContextData } = props
  const storage = React.useMemo(
    () => (storageKey ? createLocalStorage<Partial<ISudokuState>>(storageKey, JSON) : null),
    [storageKey],
  )

  const initialState = useInitialData<Partial<ISudokuState>>(storage, initialContextData ?? {})
  if (initialState === null) {
    return <CircularProgress />
  }

  return (
    <SudokuContextProvider initialState={initialState}>
      <SudokuPersistState storage={storage} />
      <SudokuGameMain />
    </SudokuContextProvider>
  )
}

const SudokuPersistState: React.FC<{ storage: IStorage<Partial<ISudokuState>> | null }> = props => {
  const { state } = React.useContext(SudokuContextType)
  usePersistSudokuStateEffect(props.storage, state)
  return <React.Fragment />
}

SudokuGame.propTypes = {
  storageKey: PropTypes.string,
  initialContextData: PropTypes.any,
}
