import type { ISudokuState } from '@kyokuya/react-game-sudoku-core'
import type { IStorage } from '@kyokuya/react-storage'
import { usePersisDataEffect } from '@kyokuya/react-storage'

const persistKeys: Array<keyof ISudokuState> = [
  'SUDOKU_SIZE_SQRT',
  'difficulty',
  'radix',
  'score',
  'attempt',
  'puzzle',
  'solution',
  'activatedCell',
  'hintCell',
  'attemptTick',
  'gameTick',
]

export const usePersistSudokuStateEffect = (
  storage: IStorage<Partial<ISudokuState>> | null,
  state: ISudokuState,
): void => {
  usePersisDataEffect<ISudokuState>(storage, state, persistKeys)
}
