import invariant from '@guanghechen/invariant'
import { useElapsedTime } from '@kyokuya/react-game-core'
import {
  SudokuActionType,
  SudokuContextType,
  checkCompleted,
} from '@kyokuya/react-game-sudoku-core'
import { Modal } from '@mui/material'
import cn from 'clsx'
import React from 'react'
import { GameOverlay } from './component/GameOverlay'
import { GameSettings } from './component/GameSettings'
import { GameToolbar } from './component/GameToolbar'
import SudokuBoard from './component/SudokuBoard'
import { SudokuInput } from './component/SudokuInput'

export const SudokuGameMain: React.FC = () => {
  const { state, dispatch } = React.useContext(SudokuContextType)
  const {
    SUDOKU_SIZE_SQRT,
    puzzle,
    solution,
    attempt,
    difficulty,
    radix,
    gameStatus,
    attemptTick,
    cheatVisible,
  } = state

  const containerRef = React.useRef<HTMLDivElement>(null)
  const sudokuValueRef = React.useRef<string>('')
  const [inputDialogVisible, setInputDialogVisible] = React.useState<boolean>(false)

  const closeCheat = React.useCallback(() => {
    dispatch({ type: SudokuActionType.TOGGLE_CHEAT_VISIBILITY, payload: false })
  }, [dispatch])

  const handleInput = React.useCallback(
    (text: string) => {
      setInputDialogVisible(false)
      sudokuValueRef.current = text

      const value = /^\s*$/.test(text) ? 0 : Number.parseInt(text, radix)
      if (Number.isInteger(value)) {
        dispatch({ type: SudokuActionType.INPUT, payload: value - 1 })
      }
    },
    [dispatch, radix],
  )

  const handleCellClick = React.useCallback(
    (r: number, c: number) => {
      if (r === -1 || c === -1 || puzzle[r][c] !== -1) return
      setInputDialogVisible(true)
    },
    [puzzle],
  )

  // Calc the score
  const usedTime: number = useElapsedTime(gameStatus)
  const SUDOKU_SIZE: number = SUDOKU_SIZE_SQRT * SUDOKU_SIZE_SQRT

  React.useEffect(() => {
    const isCompleted: boolean = checkCompleted(SUDOKU_SIZE, attempt, solution)
    if (!isCompleted) return

    let score = 0
    const totalTime: number = SUDOKU_SIZE_SQRT ** 4 * 1000
    if (usedTime < totalTime) {
      const totalScore: number = (SUDOKU_SIZE_SQRT ** 4 * difficulty) / 100
      score = ((totalTime - usedTime) * totalScore) / 1000
    }
    dispatch({
      type: SudokuActionType.FINISHED,
      payload: score,
    })
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [attemptTick])

  invariant(
    SUDOKU_SIZE_SQRT >= 2 && SUDOKU_SIZE_SQRT <= 7,
    '`childMatrixSize` must be an integer in the range [2, 7].',
  )

  return (
    <div
      ref={containerRef}
      className={cn(
        'kyokuya-sudoku',
        `kyokuya-sudoku__${gameStatus}`,
        `kyokuya-sudoku__${SUDOKU_SIZE}x${SUDOKU_SIZE}`,
      )}
    >
      <div className="kyokuya-sudoku__wrapper">
        <GameSettings />
        <GameToolbar containerRef={containerRef} />
        <div className="kyokuya-sudoku__main">
          <div className={cn('kyokuya-sudoku__main-wrapper', `kyokuya-sudoku--${gameStatus}`)}>
            <SudokuBoard
              className="kyokuya-sudoku__board--puzzle"
              attempt={attempt}
              overlay={<GameOverlay />}
              onCellClick={handleCellClick}
            />
            <Modal
              open={cheatVisible}
              container={containerRef.current}
              keepMounted={true}
              disableAutoFocus={true}
              BackdropProps={{ timeout: 500 }}
              closeAfterTransition={true}
              onClose={closeCheat}
            >
              <div className="kyokuya-sudoku__solution-wrapper" onClick={closeCheat}>
                <span className="kyokuya-sudoku__solution-close">&times;</span>
                <div onClick={e => e.stopPropagation()}>
                  <SudokuBoard className="kyokuya-sudoku__board--solution" attempt={solution} />
                </div>
              </div>
            </Modal>
          </div>
        </div>
      </div>
      <SudokuInput
        radix={state.radix}
        container={containerRef.current}
        initialValue={sudokuValueRef.current}
        visible={inputDialogVisible}
        label={`A ${radix === 10 ? 'decimal' : 'hexadecimal'} number`}
        onCancel={() => setInputDialogVisible(false)}
        onConfirm={handleInput}
      />
    </div>
  )
}
