import type { ISudokuBoard } from '@algorithm.ts/sudoku'
import { copySudokuBoard, createSudokuBoard } from '@algorithm.ts/sudoku'
import { GameRunningStatus } from '@kyokuya/react-game-core'
import { getSudokuCreator } from '../util/creator'

export interface ISudokuState {
  /**
   * Sudoku size, sqrt of the number of rows or columns.
   */
  SUDOKU_SIZE_SQRT: 2 | 3 | 4
  /**
   * Game difficulty.
   */
  difficulty: number
  /**
   * Displayed radix.
   */
  radix: 10 | 16
  /**
   * Game status.
   */
  gameStatus: GameRunningStatus
  /**
   * Total score.
   */
  score: number
  /**
   * Sudoku puzzle.
   */
  puzzle: Readonly<ISudokuBoard>
  /**
   * Solution of the puzzle.
   */
  solution: Readonly<ISudokuBoard>
  /**
   * Attempt on the puzzle.
   */
  attempt: Readonly<ISudokuBoard>
  /**
   * Currently activated board cell.
   */
  activatedCell: Readonly<{ r: number; c: number }>
  /**
   * The coordinate of the board cell for hint.
   */
  hintCell: Readonly<{ r: number; c: number; v: number }>
  /**
   * Whether to display the solution of the quiz.
   */
  cheatVisible: boolean
  /**
   * Used to judge if the game has restarted.
   */
  gameTick: number
  /**
   * Times of attempt on the current game.
   */
  attemptTick: number
  /**
   * To retrigger the hint animation when the multiple times hint requests on a
   * same cell were fired.
   */
  hintTick: number
}

export const initSudokuState = (initialState?: Partial<ISudokuState>): ISudokuState => {
  const data: Partial<ISudokuState> = { ...initialState }
  const {
    SUDOKU_SIZE_SQRT = 3,
    difficulty = 20,
    score = 0,
    radix = 10,
    activatedCell = { r: -1, c: -1 },
    gameTick = 0,
  } = data
  const SUDOKU_SIZE = SUDOKU_SIZE_SQRT * SUDOKU_SIZE_SQRT

  const { puzzle, solution } =
    data.puzzle && data.solution
      ? (data as ISudokuState)
      : getSudokuCreator(SUDOKU_SIZE_SQRT).createSudoku(difficulty / 100)

  const attempt = createSudokuBoard(SUDOKU_SIZE)
  copySudokuBoard(puzzle, attempt as ISudokuBoard)

  return {
    SUDOKU_SIZE_SQRT,
    difficulty,
    radix,
    gameStatus: GameRunningStatus.PENDING,
    score,
    attempt,
    puzzle,
    solution,
    activatedCell: { r: activatedCell.r, c: activatedCell.c },
    hintCell: { r: -1, c: -1, v: -1 },
    cheatVisible: false,
    gameTick,
    attemptTick: 0,
    hintTick: 0,
  }
}
